class NewsService{constructor(){this.news=[],this.lastUpdated=null,this.loaded=!1}async loadNews(){if(this.loaded)return this.news;try{const e=await fetch("./news-database.json");if(!e.ok)throw new Error("Failed to load news");const t=await e.json();return this.news=t.news||[],this.lastUpdated=t.lastUpdated,this.loaded=!0,console.log(`[News] Loaded ${this.news.length} news items`),this.news}catch(e){return console.error("[News] Error loading news:",e),[]}}getLatest(e=3){return this.news.slice(0,e)}getAll(){return this.news}getByCategory(e){return this.news.filter(t=>t.category.toLowerCase()===e.toLowerCase())}search(e){const t=e.toLowerCase();return this.news.filter(e=>e.title_pt.toLowerCase().includes(t)||e.summary_pt.toLowerCase().includes(t)||e.category.toLowerCase().includes(t))}formatDate(e){return new Date(e).toLocaleDateString("pt-BR",{day:"numeric",month:"short",year:"numeric"})}getCategoryIcon(e){return{expansao:"package",expansion:"package",op:"trophy","organized play":"trophy",artista:"palette",artist:"palette",produto:"shopping-bag",product:"shopping-bag",ferramenta:"wrench",tool:"wrench",evento:"calendar",event:"calendar",news:"newspaper",noticia:"newspaper"}[e.toLowerCase()]||"newspaper"}getCategoryClass(e){return{expansao:"badge-expansion",expansion:"badge-expansion",gothic:"badge-gothic",op:"badge-op","organized play":"badge-op",evento:"badge-evento",event:"badge-evento",artista:"badge-artista",artist:"badge-artista",produto:"badge-produto",product:"badge-produto",guia:"badge-guia",guide:"badge-guia",ferramenta:"badge-ferramenta",tool:"badge-ferramenta"}[e.toLowerCase()]||"badge-news"}renderCard(e,t={}){const{compact:n=!1}=t,a=this.getCategoryIcon(e.category),s=this.getCategoryClass(e.category);return n?`\n                <a href="${e.link}" target="_blank" class="news-card news-card-compact">\n                    ${e.image?`\n                        <div class="news-card-image">\n                            <img src="${e.image}" alt="${e.title_pt}" loading="lazy" onerror="this.parentElement.classList.add('no-image')">\n                        </div>\n                    `:`\n                        <div class="news-card-image no-image">\n                            <i data-lucide="${a}"></i>\n                        </div>\n                    `}\n                    <div class="news-card-body">\n                        <div class="news-badge ${s}">${e.category}</div>\n                        <h4>${e.title_pt}</h4>\n                        <p>${e.summary_pt}</p>\n                    </div>\n                </a>\n            `:`\n            <article class="news-card-full">\n                ${e.image?`\n                    <div class="news-image">\n                        <img src="${e.image}" alt="${e.title_pt}" loading="lazy" onerror="this.style.display='none'">\n                    </div>\n                `:`\n                    <div class="news-image-placeholder">\n                        <i data-lucide="${a}"></i>\n                    </div>\n                `}\n                <div class="news-content">\n                    <div class="news-meta">\n                        <span class="news-badge ${s}">\n                            ${e.category}\n                        </span>\n                        <span class="news-date">\n                            <i data-lucide="calendar"></i>\n                            ${this.formatDate(e.date)}\n                        </span>\n                    </div>\n                    <h3>${e.title_pt}</h3>\n                    <p class="news-summary">${e.summary_pt}</p>\n                    <div class="news-actions">\n                        <a href="${e.link}" target="_blank" class="btn primary btn-sm">\n                            <i data-lucide="external-link"></i>\n                            Ler Mais\n                        </a>\n                    </div>\n                </div>\n            </article>\n        `}renderLandingNews(){const e=document.getElementById("landing-news-grid");if(!e)return;const t=this.getLatest(3);0!==t.length?(e.innerHTML=t.map(e=>this.renderCard(e,{compact:!0})).join(""),"undefined"!=typeof lucide&&lucide.createIcons()):e.innerHTML='<p class="empty-state">Nenhuma noticia disponivel</p>'}renderNewsView(){const e=document.getElementById("news-content");if(!e)return;const t=this.getAll(),n=[...new Set(t.map(e=>e.category))];e.innerHTML=`\n            <div class="news-filters">\n                <div class="filter-pills">\n                    <button class="filter-pill active" data-category="all">Todas</button>\n                    ${n.map(e=>`\n                        <button class="filter-pill" data-category="${e}">${e}</button>\n                    `).join("")}\n                </div>\n                <div class="news-search">\n                    <i data-lucide="search"></i>\n                    <input type="text" id="news-search-input" placeholder="Buscar noticias...">\n                </div>\n            </div>\n\n            <div class="news-list" id="news-list">\n                ${t.map(e=>this.renderCard(e,{compact:!1})).join("")}\n            </div>\n\n            <div class="news-footer">\n                <p class="news-updated">\n                    <i data-lucide="clock"></i>\n                    Atualizado: ${this.lastUpdated?this.formatDate(this.lastUpdated):"N/A"}\n                </p>\n                <a href="https://sorcerytcg.com/news" target="_blank" class="btn ghost">\n                    <i data-lucide="external-link"></i>\n                    Ver Todas no Site Oficial\n                </a>\n            </div>\n        `,this.setupNewsFilters(),"undefined"!=typeof lucide&&lucide.createIcons()}setupNewsFilters(){const e=document.querySelectorAll(".news-filters .filter-pill");e.forEach(t=>{t.addEventListener("click",()=>{e.forEach(e=>e.classList.remove("active")),t.classList.add("active");const n=t.dataset.category;this.filterNews(n)})});const t=document.getElementById("news-search-input");if(t){let e;t.addEventListener("input",t=>{clearTimeout(e),e=setTimeout(()=>{this.searchNews(t.target.value)},300)})}}filterNews(e){const t=document.getElementById("news-list");if(!t)return;const n="all"===e?this.getAll():this.getByCategory(e);t.innerHTML=n.map(e=>this.renderCard(e,{compact:!1})).join(""),"undefined"!=typeof lucide&&lucide.createIcons()}searchNews(e){const t=document.getElementById("news-list");if(!t)return;document.querySelectorAll(".news-filters .filter-pill").forEach(e=>e.classList.remove("active")),document.querySelector('.filter-pill[data-category="all"]')?.classList.add("active");const n=e.trim()?this.search(e):this.getAll();t.innerHTML=n.length>0?n.map(e=>this.renderCard(e,{compact:!1})).join(""):'<p class="empty-state">Nenhuma noticia encontrada</p>',"undefined"!=typeof lucide&&lucide.createIcons()}openNewsDetail(e){this.news.find(t=>t.id===e)&&switchView("news")}}const newsService=new NewsService;document.addEventListener("DOMContentLoaded",async()=>{await newsService.loadNews(),newsService.renderLandingNews()}),window.newsService=newsService,console.log("[News] Service loaded");